import okhttp3.Interceptor
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import retrofit2.http.Header

interface UserApi {
    @GET("users")
    suspend fun getUsers(@Header("Authorization") token: String): List<User>
}

data class User(val id: Int, val name: String)

object NetworkModule {

    private const val BASE_URL_DEV = "https://api.example.com/"
    private const val BASE_URL_STAGING = "https://staging.api.example.com/"
    private const val BASE_URL_PRODUCTION = "https://production.api.example.com/"

    private val interceptor = Interceptor { chain ->
        val request = chain.request().newBuilder()
            .header("Authorization", "Bearer $authToken")
            .build()
        chain.proceed(request)
    }

    private var authToken: String? = null

    fun setAuthToken(token: String) {
        authToken = token
    }

    suspend fun getUsers(apiEnvironment: ApiEnvironment): List<User> {
        val client = OkHttpClient.Builder()
            .addInterceptor(interceptor)
            .build()

        val retrofit = Retrofit.Builder()
            .baseUrl(getBaseUrl(apiEnvironment))
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build()

        val api = retrofit.create(UserApi::class.java)
        return api.getUsers("Bearer $authToken")
    }

    private fun getBaseUrl(apiEnvironment: ApiEnvironment): String {
        return when (apiEnvironment) {
            ApiEnvironment.DEV -> BASE_URL_DEV
            ApiEnvironment.STAGING -> BASE_URL_STAGING
            ApiEnvironment.PRODUCTION -> BASE_URL_PRODUCTION
        }
